  ('diplomatic-535efab1-moex-00693', 'diplomatic-535efab1', 'diplomatic-535efab1-moex-110-c655adf3', 'sub-diplomatic-535efab1-05', NULL, 'single_choice', '依司法院釋字第756號解釋意旨，關於憲法秘密通訊自由，下列敘述何者錯誤？', '["受刑人在監禁期間，人身自由遭受限制，惟其秘密通訊自由等基本權利，仍受憲法之保障", "監獄長官閱讀受刑人發受書信，涉及對秘密通訊自由核心內涵之干預", "監獄長官為確認有無夾帶違禁品而檢查受刑人書信，並不當然影響通訊內容之秘密性", "監獄長官令受刑人刪除書信部分內容後再發出，如以法律或法律具體明確授權之命令定之，即為憲法所許"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:37+00:00", "source_pdf_sha1": "4869a4c6fee1", "answer_pdf_sha1": "9956c1dccdce", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "101", "s": "0604", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "綜合法政知識(包括中華民國憲法、兩岸關係、比較政府與政治)", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-英文組"}'::jsonb, NULL),
